// ── igr-004 full rebuild: Subject Access Requests ──
export const IGR004_CONTENT_V2: DocumentContent = {
  title: "Subject Access Request Procedure",
  policyId: "IGR-004",
  version: "2.0",
  reviewedBy: "Registered Manager / Data Protection Lead",
  purpose: "This policy delivers the right of access properly: when a person asks to see their information, they get it — complete, comprehensible, on time and free — with third parties protected and the narrow exemptions applied as exceptions rather than reflexes. The right of access is how people check what is held and said about them; a service confident in its records (pc-004's write-for-the-reader standard) has nothing to manage here but logistics.",
  scope: "Covers requests for personal data from the people the service supports, staff and others whose data it holds; requests via representatives, attorneys and deputies; requests concerning children and the deceased; and the interfaces with routine record-sharing (the person reading their own care plan needs no SAR — dc-009's rights and pc-004's online access carry everyday transparency, and this procedure exists for the formal cases).",
  responsibilities: [
    { role: "Registered Manager / Data Protection Lead", duties: [
      "Recognise and log every SAR on the day it arrives — however it arrives: requests need no form, no magic words and no particular addressee",
      "Run the one-month clock (with the lawful extension only for genuinely complex cases, communicated within the first month with reasons)",
      "Gather across every system the data lives in, apply the third-party and exemption screens with reasoning recorded, and deliver in the format the person can use",
      "Maintain the SAR log and report performance through governance" ] },
    { role: "All Staff", duties: [
      "Route anything that might be a SAR to the manager the same day — 'I want to see everything you've written about me', said verbally to a care worker, is a valid request from that moment",
      "Never obstruct, delay or discourage a request, and never purge or 'tidy' records after one arrives — post-request alteration is unlawful and treated as records falsification (pc-004)",
      "Keep everyday transparency generous so SARs stay rare: the person asking about their own care plan is shown it, today, per dc-009 and su-005" ] },
  ],
  keyPoints: [
    "A SAR is any request, in any form, through any channel: verbal, letter, email, via the platform, to any member of staff — no form may be required (a form may be offered to help scope, never to gate), and the clock starts on receipt, not on the form's return",
    "The clock is one calendar month, free of charge: extendable by up to two further months only where requests are genuinely complex or numerous, with the extension and its reasons communicated inside the first month; fees are charged only for manifestly unfounded or excessive requests (rare, evidenced, and decided at provider level) or for additional copies",
    "Identity is verified proportionately: enough to be confident the requester is the person or lawfully acting for them — the resident the service sees daily needs no passport ritual; the email claiming to be a relative needs verification (dc-015's callback discipline); and verification requests pause the clock only where genuinely necessary and promptly made",
    "Representatives need authority, not relationship: attorneys and deputies within the scope of their instrument (dc-011's authority map), written consent for anyone else acting on a person's behalf, and requests concerning people who lack capacity handled through best-interests machinery where no lawful representative exists — with the person's own right preserved (impaired capacity does not extinguish the right of access; support to exercise it comes first, per dc-009's ladder)",
    "The gather is exhaustive by checklist: the care record (digital and paper), daily notes and MARs, the home record where community services keep one (dc-007), incident, safeguarding, complaint and candour entries concerning the person, emails and messages where they are about the person (searched by name and known identifiers), CCTV or monitoring data where held (bb-001), finance records (ch-006/dc-011), and photographs — the checklist at Appendix A exists because the commonest SAR failure is the forgotten system",
    "Third parties are protected by redaction, not refusal: information about other people (other residents in shared entries, relatives' confidences, staff in personal contexts) is redacted or summarised unless consent or reasonableness permits disclosure — applied line-by-line with a light hand (the request is for the person's data, and over-redaction that makes the record gibberish fails the duty) and the reasoning noted for contested calls; professionals acting in their professional capacity are not 'third parties' to hide",
    "Exemptions are narrow and reasoned: serious-harm (health data whose disclosure would likely cause serious harm to the person or another — applied on appropriate clinical advice, not managerial nervousness), safeguarding and crime interfaces, legal privilege, and confidential references — each applied to the specific material, recorded with reasons, and never used to withhold what is merely uncomfortable (the critical care note the family will dislike is disclosable; discomfort is not harm)",
    "Delivery matches the person: secure transmission, plain-language covering note explaining what is included and any redactions in general terms, accessible formats where needed (large print, the su-005 promise honoured — help reading the disclosure offered), and the follow-up rights explained (corrections via pc-004's amendment machinery, complaint to the service and the ICO)",
    "Special cases have their own routes: staff SARs (same machinery; hr records gathered with the same rigour, references handled per their exemption); children (Gillick-competent young people exercise their own right — pc-003's framework); the deceased (UK GDPR ends at death — Access to Health Records Act 1990 governs health records for personal representatives and dependants' claims, and the service routes such requests accordingly); and post-request record integrity absolute in all of them",
  ],
  legislation: [
    "UK GDPR Article 15 (right of access) and Article 12 (modalities, timescales)",
    "Data Protection Act 2018 (exemptions, Schedule 2 and 3 provisions)",
    "Access to Health Records Act 1990 (deceased persons)",
    "Mental Capacity Act 2005 (representatives, best interests, supported exercise of the right)",
    "Health and Social Care Act 2008 (Regulated Activities) Regulations 2014 — Regulation 17",
  ],
  sections: [
    { title: "Receiving and scoping", body: "Recognition is trained wide: any expression of 'I want to see my records/what you hold/what you've written' is logged as a SAR the day it is made, whoever received it and however informally — the care worker who hears it at a kitchen table routes it to the manager the same day (dc-007's boundary machinery), and the log entry records the request's date, form, requester and scope. Scoping is a service, not a hurdle: a conversation (offered, not required) clarifying what the person actually wants — often a specific period, a specific incident, a specific worry — which shortens the gather and improves the answer; but a person who wants everything gets everything, and the scoping offer never becomes pressure to narrow. Verification runs proportionately and promptly (the clock pauses only for genuinely necessary verification, and the ask goes out within days, not at week three); representative requests are checked against authority (the instrument's scope read, not assumed — a property-and-affairs LPA does not automatically reach health records); and everyday-transparency triage catches the requests that need no procedure at all: the person asking to read their care plan is shown it today, with the SAR machinery reserved for the formal, the historical and the comprehensive." },
    { title: "The gather", body: "The gather runs the checklist across every repository, because completeness is the duty's heart: the digital care record (full export for the scope, including audit-trail entries where they contain the person's data), paper records and archives (igr-005's storage searched, not just the live file), the community home record collected or copied (dc-007), MARs and clinical charts, incident/safeguarding/complaint/candour entries concerning the person (with third-party screens applied later, not used as an excuse to skip the gather), email and message searches by name and identifiers across the service's accounts (the search terms logged), monitoring and telecare data where held (bb-001's records), CCTV where operated (retention windows checked immediately — footage cycles fast, and a SAR freezes relevant footage), financial records (ch-006/dc-011), photographs and their consents, and staff-held materials (the notebook habit surfaced honestly — unofficial notes about a person are still their personal data). Two disciplines govern throughout: preservation (from the moment a SAR arrives, nothing within its scope is deleted, altered or 'tidied' — routine deletion schedules are suspended for the scope, and post-request alteration is treated as falsification with pc-404-grade seriousness) and logging (what was searched, by whom, with what terms — the gather's audit trail is the answer to 'did you really look everywhere?')." },
    { title: "Screening: third parties and exemptions", body: "Screening happens line-by-line with a bias to disclosure. Third-party material: other residents appearing in shared entries are redacted or the entry summarised to the requester's own thread; relatives' confidences shared in confidence are assessed against the reasonableness factors (their expectation, the content's nature, the requester's need) with consent sought where practical; staff appear unredacted in their professional capacity (who delivered care, what they recorded) and protected in genuinely personal contexts; and the redaction hand stays light — the duty is to disclose the person's data, and a document redacted into confetti fails it. Exemptions: the serious-harm test for health information is applied only on appropriate clinical advice (the GP or relevant professional consulted, the advice recorded) and construed narrowly — likely serious harm to physical or mental health, not distress, not awkwardness, not the family argument the note might spark; safeguarding and crime-prevention interfaces are applied where disclosure would prejudice protection or investigation (the safeguarding lead consulted where the record touches live protection work — the abuser-as-requester scenario screened explicitly, especially in representative requests: authority is checked against motive where protection concerns exist, and safeguarding outranks paperwork); legal privilege and confidential references carry their specific exemptions. Every application of any screen is recorded — material withheld or redacted, ground, reasoning — both for the person's complaint rights and for the ICO's later questions, and the covering letter tells the person in general terms that redactions were made and why kinds, so the screens themselves stay honest." },
    { title: "Delivery, follow-up and governance", body: "Delivery completes the right, not just the process: secure transmission matched to the material's sensitivity (encrypted digital delivery, tracked post, or collection with identity confirmed), a covering note in plain language (what is enclosed, the period covered, what was searched, redaction kinds and grounds in general terms, and who to contact with questions), accessible formats honoured (large print, supported reading sessions per su-005's promise — the offer to sit with the person and help them understand their own record is care, not concession), and the follow-up rights stated: corrections requested via pc-004's amendment machinery (errors fixed visibly, disagreements recorded as the person's noted dissent), complaints to the service via res-001, and the ICO's route with contact details. Special-route requests deliver per their frameworks: staff SARs with the same completeness (and the same third-party care for colleagues and references), deceased-person requests under the 1990 Act's gates (personal representatives and dependants' claims, health records scope), and children per competence. Governance closes the loop: the SAR log tracks volumes, timescales (receipt→acknowledgement→delivery against the clock), extensions and their reasons, exemption usage (a rising serious-harm usage rate is a red flag for reflex, audited), and outcomes (complaints, corrections requested — each correction request also feeding pc-004's record-quality learning); quarterly reporting through governance; and the annual test asked from the person's side: could our most anxious resident get everything we hold about them, understand it, and correct it — inside a month, without a fight?" },
  ],
  appendices: [
    { title: "Appendix A — SAR Handling Checklist & Timeline", type: "checklist", body:
"DAY 0 (receipt — any form, any channel, any staff member): [ ] logged same day (date, form, requester, scope) [ ] acknowledged with timeline [ ] everyday-transparency triage (care-plan request → shown TODAY, no SAR needed) [ ] scoping conversation OFFERED (never required/pressured)\nWEEK 1: [ ] identity/authority verified proportionately (clock pauses only if genuinely necessary; ask sent promptly) [ ] representative authority READ for scope (LPA type checked; abuser-as-requester screen where protection concerns — safeguarding lead consulted) [ ] PRESERVATION: deletion schedules suspended for scope; post-request alteration = falsification [ ] gather started per checklist: digital record | paper & archive | home record (dc-007) | MARs/charts | incident/safeguarding/complaint/candour | email & message searches (terms logged) | monitoring/telecare (bb-001) | CCTV (footage FROZEN — retention cycles fast) | finance (ch-006/dc-011) | photos | staff-held notes\nWEEKS 2–3: [ ] third-party screen line-by-line (light hand; professionals-in-role not redacted) [ ] exemptions on clinical advice only, narrowly (distress ≠ harm), all reasoning recorded [ ] complex/numerous → extension decided & COMMUNICATED with reasons inside month one\nDELIVERY (within 1 calendar month): [ ] secure route matched to sensitivity [ ] plain-language covering note (contents, searches, redaction kinds & grounds) [ ] accessible format / supported reading offered (su-005) [ ] follow-up rights stated (corrections via pc-004, res-001, ICO)\nLOG CLOSED: timescales, exemption usage, outcome → quarterly governance" },
    { title: "Appendix B — SAR Log (structure)", type: "template", body:
"Ref | received (date/channel/staff member) | requester (person/staff/representative — authority evidence) | scope | identity verified (date/method/clock-pause days) | acknowledgement sent | gather completed (checklist attached, search terms logged) | screens applied (third-party redactions n / exemptions: ground, clinical advice ref, reasoning) | extension (reasons, communicated date) | delivered (date, route, format) | within clock? | follow-up (corrections requested → pc-004 learning / complaint / ICO contact)\nQUARTERLY REVIEW: volumes | timescale performance | extension rate | EXEMPTION USAGE TREND (rising serious-harm rate = reflex red flag, audited) | correction requests → record-quality learning\nANNUAL TEST: could our most anxious resident get everything, understand it, and correct it — inside a month, without a fight?" },
  ],
  monitoring: "SAR log reviewed monthly by the data protection lead and quarterly through governance; timescale and exemption-usage trends audited; annual review including the person-side test; procedure reviewed annually and on regulatory change.",
  relatedDocuments: ["igr-002 — Confidentiality Policy", "igr-001 — Records Management Policy", "igr-005 — Retention and Disposal Schedule", "pc-004 — Patient Records Policy (amendments, online access)", "dc-011 — Financial Support & Appointeeship Boundaries (authority map)", "su-005 — Easy Read: Your Information and Privacy"],
};

